import type { Metadata, Viewport } from "next";
import { Inter, JetBrains_Mono } from "next/font/google";
import "./globals.css";

const inter = Inter({
  subsets: ["latin"],
  variable: "--font-sans",
  display: "swap",
});

const jetbrainsMono = JetBrains_Mono({
  subsets: ["latin"],
  variable: "--font-mono",
  display: "swap",
});

export const metadata: Metadata = {
  title: {
    default: "Notepad Workspace",
    template: "%s | Notepad Workspace",
  },
  description:
    "A modern, clean notepad foundation built with Next.js for creating, editing, and managing text documents.",
  applicationName: "Notepad Workspace",
  keywords: [
    "notepad",
    "text editor",
    "notes",
    "next.js",
    "local files",
    "rtf",
    "txt",
  ],
  authors: [{ name: "Notepad Workspace" }],
  creator: "Notepad Workspace",
  metadataBase: new URL("http://localhost:3000"),
  icons: {
    icon: "/favicon.ico",
    shortcut: "/favicon.ico",
    apple: "/favicon.ico",
  },
};

export const viewport: Viewport = {
  width: "device-width",
  initialScale: 1,
  themeColor: [
    { media: "(prefers-color-scheme: light)", color: "#f8fafc" },
    { media: "(prefers-color-scheme: dark)", color: "#020617" },
  ],
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en" suppressHydrationWarning>
      <body className={`${inter.variable} ${jetbrainsMono.variable} app-body`}>
        <div className="app-shell">
          <header className="app-header" role="banner">
            <div className="app-header__inner">
              <div className="app-branding">
                <p className="app-branding__eyebrow">Production Scaffold</p>
                <h1 className="app-branding__title">Notepad Workspace</h1>
              </div>
              <p className="app-header__meta" aria-label="Application status">
                Ready for editor features
              </p>
            </div>
          </header>

          <main className="app-main" role="main">
            {children}
          </main>

          <footer className="app-footer" role="contentinfo">
            <p>
              Built with Next.js App Router · Responsive shell · Accessible design
              baseline
            </p>
          </footer>
        </div>
      </body>
    </html>
  );
}

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  color-scheme: light;

  --font-sans: Inter, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
  --font-mono: "JetBrains Mono", ui-monospace, SFMono-Regular, Menlo, Monaco,
    Consolas, "Liberation Mono", "Courier New", monospace;

  --background: #f8fafc;
  --background-soft: #f1f5f9;
  --surface: #ffffff;
  --surface-raised: #ffffff;
  --text-primary: #0f172a;
  --text-secondary: #475569;
  --text-muted: #64748b;
  --border: #dbe3ef;
  --border-strong: #b9c7dd;
  --accent: #2563eb;
  --accent-hover: #1d4ed8;
  --accent-soft: #dbeafe;
  --danger: #dc2626;
  --success: #16a34a;

  --radius-sm: 0.5rem;
  --radius-md: 0.75rem;
  --radius-lg: 1rem;

  --shadow-sm: 0 1px 2px rgba(2, 8, 23, 0.07);
  --shadow-md: 0 8px 24px rgba(15, 23, 42, 0.09);
  --shadow-lg: 0 20px 40px rgba(15, 23, 42, 0.12);

  --ring: 0 0 0 3px rgba(37, 99, 235, 0.25);

  --max-content-width: 1120px;
}

@media (prefers-color-scheme: dark) {
  :root {
    color-scheme: dark;

    --background: #020617;
    --background-soft: #0b1220;
    --surface: #0f172a;
    --surface-raised: #111b31;
    --text-primary: #e2e8f0;
    --text-secondary: #cbd5e1;
    --text-muted: #94a3b8;
    --border: #22314d;
    --border-strong: #334666;
    --accent: #60a5fa;
    --accent-hover: #93c5fd;
    --accent-soft: rgba(96, 165, 250, 0.18);
    --danger: #f87171;
    --success: #4ade80;

    --shadow-sm: 0 1px 2px rgba(2, 6, 23, 0.5);
    --shadow-md: 0 8px 24px rgba(2, 6, 23, 0.5);
    --shadow-lg: 0 20px 40px rgba(2, 6, 23, 0.6);
  }
}

@layer base {
  * {
    box-sizing: border-box;
  }

  *:focus-visible {
    outline: none;
    box-shadow: var(--ring);
    border-radius: 0.35rem;
  }

  html,
  body {
    width: 100%;
    min-height: 100%;
    margin: 0;
    padding: 0;
  }

  body {
    background:
      radial-gradient(circle at top left, var(--accent-soft), transparent 40%),
      linear-gradient(to bottom, var(--background-soft), var(--background));
    color: var(--text-primary);
    font-family: var(--font-sans);
    text-rendering: optimizeLegibility;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    line-height: 1.5;
  }

  h1,
  h2,
  h3,
  h4,
  h5,
  h6,
  p {
    margin: 0;
  }

  button,
  input,
  textarea,
  select {
    font: inherit;
    color: inherit;
  }

  ::selection {
    background: var(--accent-soft);
    color: var(--text-primary);
  }

  ::-webkit-scrollbar {
    width: 11px;
    height: 11px;
  }

  ::-webkit-scrollbar-track {
    background: transparent;
  }

  ::-webkit-scrollbar-thumb {
    background: color-mix(in srgb, var(--text-muted) 45%, transparent);
    border-radius: 9999px;
    border: 2px solid transparent;
    background-clip: content-box;
  }

  ::-webkit-scrollbar-thumb:hover {
    background: color-mix(in srgb, var(--text-secondary) 65%, transparent);
    background-clip: content-box;
  }
}

.app-body {
  min-height: 100dvh;
}

.app-shell {
  min-height: 100dvh;
  display: grid;
  grid-template-rows: auto 1fr auto;
}

.app-header {
  position: sticky;
  top: 0;
  z-index: 40;
  border-bottom: 1px solid var(--border);
  background: color-mix(in srgb, var(--surface) 88%, transparent);
  backdrop-filter: blur(8px);
  box-shadow: var(--shadow-sm);
}

.app-header__inner {
  margin-inline: auto;
  max-width: var(--max-content-width);
  padding: 0.9rem 1rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
}

.app-branding {
  display: flex;
  flex-direction: column;
  gap: 0.1rem;
}

.app-branding__eyebrow {
  font-size: 0.68rem;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--text-muted);
  font-weight: 700;
}

.app-branding__title {
  font-size: 1rem;
  letter-spacing: -0.01em;
  font-weight: 650;
}

.app-header__meta {
  font-size: 0.82rem;
  color: var(--text-secondary);
  background: var(--surface-raised);
  border: 1px solid var(--border);
  border-radius: 9999px;
  padding: 0.35rem 0.7rem;
  white-space: nowrap;
}

.app-main {
  width: min(var(--max-content-width), 100%);
  margin-inline: auto;
  padding: 1rem;
}

.app-footer {
  border-top: 1px solid var(--border);
  color: var(--text-muted);
  font-size: 0.8rem;
  padding: 0.8rem 1rem 1.1rem;
  text-align: center;
}

@media (max-width: 768px) {
  .app-header__inner {
    padding: 0.8rem 0.75rem;
  }

  .app-header__meta {
    display: none;
  }

  .app-main {
    padding: 0.75rem;
  }

  .app-footer {
    padding: 0.7rem 0.75rem 0.95rem;
  }
}

@media (min-width: 1024px) {
  .app-main {
    padding: 1.25rem;
  }
}

@layer components {
  .surface-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-md);
  }

  .surface-card--raised {
    background: var(--surface-raised);
    box-shadow: var(--shadow-lg);
  }

  .control-button {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 0.45rem;
    border-radius: var(--radius-sm);
    border: 1px solid var(--border);
    background: var(--surface-raised);
    color: var(--text-primary);
    padding: 0.5rem 0.75rem;
    font-size: 0.875rem;
    font-weight: 550;
    cursor: pointer;
    transition:
      transform 120ms ease,
      border-color 120ms ease,
      background-color 120ms ease;
  }

  .control-button:hover {
    transform: translateY(-1px);
    border-color: var(--border-strong);
  }

  .control-button:active {
    transform: translateY(0);
  }

  .control-button--primary {
    background: var(--accent);
    color: #ffffff;
    border-color: transparent;
  }

  .control-button--primary:hover {
    background: var(--accent-hover);
  }

  .text-field {
    width: 100%;
    border-radius: var(--radius-sm);
    border: 1px solid var(--border);
    background: var(--surface);
    padding: 0.55rem 0.65rem;
    transition: border-color 120ms ease;
  }

  .text-field:hover {
    border-color: var(--border-strong);
  }

  .mono {
    font-family: var(--font-mono);
  }
}
